/* Compasso · Journaling integrado: registrar, revisar, decidir e transformar */
const journalModel = globalThis.CompassoJournalModel;
if (!journalModel) throw new Error('CompassoJournalModel não foi carregado.');

state.data = journalModel.migrateState(state.data);
labels.journal = { title: 'Journaling', kicker: 'Registro e reflexão' };

const JOURNAL_TYPE_LABELS = { task:'Tarefa', event:'Evento', note:'Nota', learning:'Aprendizado', reflection:'Reflexão', gratitude:'Gratidão', question:'Pergunta', decision:'Decisão' };
const JOURNAL_TYPE_MARKS = { task:'•', event:'○', note:'–', learning:'!', reflection:'◇', gratitude:'+', question:'?', decision:'◆' };
const JOURNAL_STATUS_LABELS = { open:'Aberta', completed:'Concluída', migrated:'Migrada', scheduled:'Planejada', delegated:'Delegada', cancelled:'Cancelada', archived:'Arquivada' };
const JOURNAL_STATUS_MARKS = { open:'•', completed:'✓', migrated:'→', scheduled:'⇢', delegated:'@', cancelled:'×', archived:'□' };
const JOURNAL_SIGNIFIER_LABELS = { priority:'Prioridade', important:'Importante', urgent:'Urgente', inspiration:'Inspiração', blocked:'Bloqueio', follow_up:'Acompanhamento', waiting:'Aguardando resposta', high_energy:'Energia alta', low_energy:'Energia baixa' };
const JOURNAL_MOODS = { very_low:'Muito difícil', low:'Difícil', neutral:'Neutro', good:'Bom', great:'Muito bom' };
const JOURNAL_SHORTCUTS = { '/tarefa':'task', '/evento':'event', '/nota':'note', '/aprendizado':'learning', '/reflexão':'reflection', '/reflexao':'reflection', '/gratidão':'gratitude', '/gratidao':'gratitude', '/pergunta':'question', '/decisão':'decision', '/decisao':'decision' };
const JOURNAL_EVENTS = ['journal:entry-created','journal:entry-updated','journal:entry-deleted','journal:entry-archived','journal:entry-transformed','journal:task-completed','journal:task-migrated','journal:day-closed','journal:month-reviewed','journal:collection-created','journal:collection-updated'];

const journalRuntime = {
  mode: 'day',
  date: journalModel.dateKey(),
  month: journalModel.dateKey().slice(0, 7),
  editingId: null,
  migratingId: null,
  transformId: null,
  sessionSourceId: null,
  search: '',
  type: '',
  status: '',
  signifier: '',
  collection: '',
  concealPreviews: localStorage.getItem('compasso.journal.conceal.v1') === 'true'
};

function journalNow() { return new Date().toISOString(); }
function journalDateOffset(key, amount) { const value = new Date(`${key}T12:00:00`); value.setDate(value.getDate() + amount); return journalModel.dateKey(value); }
function journalMonthOffset(key, amount) { const [year, month] = key.split('-').map(Number); const value = new Date(year, month - 1 + amount, 1, 12); return journalModel.dateKey(value).slice(0, 7); }
function journalEntry(id) { return state.data.journalEntries.find(item => item.id === id) || null; }
function journalDay(key = journalRuntime.date) { return state.data.dailyJournals[key] || journalModel.dailyJournal(null, key); }
function journalSave(message) { state.data = journalModel.migrateState(state.data); saveData(message); }
function journalEmit(name, entry, extra = {}) { CompassoFeatures.emit(name, { id: entry?.id || null, date: entry?.date || null, entryType: entry?.entryType || null, timestamp: journalNow(), ...extra }); }
function journalReplace(entry) { const index = state.data.journalEntries.findIndex(item => item.id === entry.id); if (index >= 0) state.data.journalEntries[index] = entry; else state.data.journalEntries.unshift(entry); }
function journalDateLabel(key, options = {}) { return new Intl.DateTimeFormat('pt-BR', { weekday:'long', day:'2-digit', month:'long', year:'numeric', ...options }).format(new Date(`${key}T12:00:00`)); }
function journalDuration(ms) { const minutes = Math.max(0, Math.round(Number(ms || 0) / 60000)); const hours = Math.floor(minutes / 60); return hours ? `${hours}h ${String(minutes % 60).padStart(2,'0')}min` : `${minutes} min`; }
function journalCompletedSessions(key) { return (state.data.sessions || []).filter(item => item.status === 'completed' && journalModel.dateKey(item.endedAt || item.startedAt) === key); }
function journalRefs() {
  const values = [];
  ['goal','study','reading'].forEach(type => (state.data[type] || []).forEach(item => values.push({ type, id:item.id, title:item.title, detail:domainLabels[type] })));
  const plan = typeof todayPlan === 'function' ? todayPlan() : null;
  (plan?.items || []).forEach(item => item.id && values.push({ type:'action', id:item.id, title:item.title || todayItem(item)?.note || todayItem(item)?.title || 'Ação', detail:'Ação de Hoje' }));
  (state.data.notes || []).forEach(item => values.push({ type:'note', id:item.id, title:item.title, detail:'Nota do Atlas' }));
  (state.data.sessions || []).slice(0,30).forEach(item => values.push({ type:'session', id:item.id, title:state.data[item.domain]?.find(source => source.id === item.itemId)?.title || 'Sessão', detail:'Sessão' }));
  return values;
}
function journalRefLabel(ref) { const item = journalRefs().find(value => value.type === ref.type && value.id === ref.id); return item ? `${item.detail}: ${item.title}` : `${ref.type}: ${ref.id}`; }
function journalParseCapture(raw, fallback) {
  const value = String(raw || '').trim();
  const shortcut = Object.keys(JOURNAL_SHORTCUTS).find(key => value.toLocaleLowerCase('pt-BR').startsWith(`${key} `) || value.toLocaleLowerCase('pt-BR') === key);
  return { entryType: shortcut ? JOURNAL_SHORTCUTS[shortcut] : fallback || 'note', content: shortcut ? value.slice(shortcut.length).trim() : value };
}

