function journalInstallUi() {
  if (!document.querySelector('[data-view="journal"]')) {
    const anchor = document.querySelector('[data-view="today"]') || document.querySelector('[data-view="overview"]');
    anchor?.insertAdjacentHTML('afterend', `<button class="nav-item" data-view="journal">${icon('note')}<span>Journaling</span><span class="nav-badge" id="journalBadge"></span></button>`);
  }
  if (!document.getElementById('journalView')) document.querySelector('.content')?.insertAdjacentHTML('afterbegin', `<section class="view" id="journalView"><div class="journal-shell"><section class="journal-hero"><div><div class="eyebrow">Journaling no Compasso</div><h2>Registre para clarear.<br>Revise para decidir.</h2><p>Uma linha contínua entre intenção, execução e aprendizado.</p></div><div class="journal-private">▣ Privado e local-first <button class="quiet-btn" type="button" data-journal-conceal></button></div></section><nav class="journal-tabs" aria-label="Visões do Journaling"><button type="button" data-journal-mode="day">Diário</button><button type="button" data-journal-mode="month">Mês</button><button type="button" data-journal-mode="future">Futuro</button><button type="button" data-journal-mode="collections">Coleções</button></nav><div id="journalSurface"></div></div></section>`);
  if (!document.getElementById('journalEntryDialog')) document.body.insertAdjacentHTML('beforeend', `
    <dialog class="journal-dialog" id="journalEntryDialog"><form id="journalEntryForm" method="dialog"><div class="journal-dialog-head"><div><div class="eyebrow">Entrada do Journal</div><h2 id="journalEntryTitle">Editar entrada</h2></div><button class="close-btn" type="button" data-journal-close="journalEntryDialog">${icon('x')}</button></div><div class="journal-form"><label>Conteúdo<textarea id="journalEntryContent" maxlength="5000" required></textarea></label><div class="journal-form-grid"><label>Tipo<select id="journalEntryType">${Object.entries(JOURNAL_TYPE_LABELS).map(([value,label]) => `<option value="${value}">${label}</option>`).join('')}</select></label><label>Data<input id="journalEntryDate" type="date" required></label><label>Estado da tarefa<select id="journalEntryStatus"><option value="open">Aberta</option><option value="completed">Concluída</option><option value="scheduled">Planejada</option><option value="delegated">Delegada</option><option value="cancelled">Cancelada</option><option value="archived">Arquivada</option></select></label><label>Vínculo<select id="journalEntryRef"></select></label><label>Coleção<select id="journalEntryCollection"></select></label><label>Humor opcional<select id="journalEntryMood"><option value="">Não registrar</option>${Object.entries(JOURNAL_MOODS).map(([value,label]) => `<option value="${value}">${label}</option>`).join('')}</select></label><label>Energia opcional<select id="journalEntryEnergy"><option value="">Não registrar</option>${[1,2,3,4,5].map(value => `<option value="${value}">${value} de 5</option>`).join('')}</select></label></div><label>Tags<input id="journalEntryTags" placeholder="trabalho, spark, decisão"></label><div><span class="eyebrow">Marcadores</span><div class="journal-checks">${Object.entries(JOURNAL_SIGNIFIER_LABELS).map(([value,label]) => `<label><input type="checkbox" name="journalSignifier" value="${value}">${label}</label>`).join('')}</div></div><div class="journal-checks"><label><input id="journalEntryPinned" type="checkbox">Fixar</label><label><input id="journalEntryPrivate" type="checkbox" checked>Entrada privada</label></div></div><div class="journal-dialog-foot"><button class="quiet-btn" type="button" data-journal-close="journalEntryDialog">Cancelar</button><button class="primary-btn" type="submit">Salvar entrada</button></div></form></dialog>
    <dialog class="journal-dialog" id="journalMigrationDialog"><form id="journalMigrationForm" method="dialog"><div class="journal-dialog-head"><div><div class="eyebrow">Migração consciente</div><h2>Esta tarefa ainda merece seu tempo?</h2></div><button class="close-btn" type="button" data-journal-close="journalMigrationDialog">${icon('x')}</button></div><div class="journal-form"><div class="journal-entry-content" id="journalMigrationContent"></div><div class="journal-form-grid"><label>Decisão<select id="journalMigrationDecision"><option value="tomorrow">Sim, executar amanhã</option><option value="date">Sim, escolher outra data</option><option value="future">Sim, mas não agora</option><option value="delegate">Delegar</option><option value="project">Transformar em projeto</option><option value="cancel">Cancelar</option><option value="archive">Arquivar como referência</option></select></label><label>Data<input id="journalMigrationDate" type="date"></label></div><label>Por que ainda não foi concluída? (opcional)<select id="journalMigrationReason"><option value="">Não informar</option><option value="lack_of_time">Não houve tempo</option><option value="low_priority">Baixa prioridade</option><option value="too_large">Tarefa grande demais</option><option value="unclear">Falta de clareza</option><option value="external_dependency">Dependência externa</option><option value="low_energy">Falta de energia</option><option value="forgotten">Esquecimento</option><option value="technical_block">Bloqueio técnico</option><option value="not_relevant">Deixou de ser relevante</option><option value="other">Outro</option></select></label></div><div class="journal-dialog-foot"><button class="quiet-btn" type="button" data-journal-close="journalMigrationDialog">Voltar</button><button class="primary-btn" type="submit">Confirmar decisão</button></div></form></dialog>
    <dialog class="journal-dialog" id="journalTransformDialog"><form id="journalTransformForm" method="dialog"><div class="journal-dialog-head"><div><div class="eyebrow">Transformar sem perder a origem</div><h2>Levar adiante</h2></div><button class="close-btn" type="button" data-journal-close="journalTransformDialog">${icon('x')}</button></div><div class="journal-form"><div class="journal-entry-content" id="journalTransformContent"></div><label>Destino<select id="journalTransformTarget"><option value="note">Nota permanente</option><option value="action">Próxima ação em Hoje</option><option value="capture">Captura do Segundo Cérebro</option><option value="recall">Pergunta de Active Recall</option><option value="evidence">Evidência</option></select></label><label id="journalTransformExtraWrap">Resposta ou detalhe<textarea id="journalTransformExtra" maxlength="1800" placeholder="Para Active Recall, escreva a resposta de referência. Para evidência, detalhe o resultado."></textarea></label></div><div class="journal-dialog-foot"><button class="quiet-btn" type="button" data-journal-close="journalTransformDialog">Cancelar</button><button class="primary-btn" type="submit">Transformar</button></div></form></dialog>
    <dialog class="journal-dialog" id="journalCloseDialog"><form id="journalCloseForm" method="dialog"><div class="journal-dialog-head"><div><div class="eyebrow">Encerramento opcional</div><h2>Fechar o dia com decisões</h2></div><button class="close-btn" type="button" data-journal-close="journalCloseDialog">${icon('x')}</button></div><div class="journal-form"><div id="journalCloseSummary" class="journal-entry-content"></div><div><span class="eyebrow">Pendências</span><div class="journal-close-tasks" id="journalCloseTasks"></div></div><div class="journal-review">${[['important','O que foi mais importante hoje?'],['progress','O que avancei?'],['pending','O que ficou pendente?'],['learned','O que aprendi?'],['drained','O que drenou minha atenção?'],['tomorrow','O que deve receber atenção amanhã?']].map(([key,label]) => `<label>${label}<textarea name="${key}" maxlength="1200"></textarea></label>`).join('')}</div></div><div class="journal-dialog-foot"><button class="quiet-btn" type="button" data-journal-close="journalCloseDialog">Deixar aberto</button><button class="primary-btn" type="submit">Encerrar o dia</button></div></form></dialog>
  `);
  if (!document.getElementById('journalExportSetting')) settingsMenu?.insertAdjacentHTML('beforeend', `<label id="journalExportSetting" style="display:flex;gap:8px;align-items:center;padding:8px 12px;font-size:9px"><input id="journalExportToggle" type="checkbox" checked>Incluir Journaling nas exportações JSON</label>`);
}

function journalEntryMarkup(entry) {
  const status = entry.entryType === 'task' ? entry.taskStatus : null;
  const mark = status ? JOURNAL_STATUS_MARKS[status] : JOURNAL_TYPE_MARKS[entry.entryType];
  const completed = status === 'completed', muted = ['migrated','cancelled','archived'].includes(status);
  const chips = [...entry.signifiers.map(value => `<span class="journal-chip ${['urgent','blocked'].includes(value) ? 'alert' : ''}">${escapeHtml(JOURNAL_SIGNIFIER_LABELS[value])}</span>`), ...entry.tags.map(value => `<span class="journal-chip">#${escapeHtml(value)}</span>`), ...entry.linkedRefs.map(value => `<span class="journal-chip">${escapeHtml(journalRefLabel(value))}</span>`)];
  if (entry.metadata.migrationCount >= 3) chips.push(`<span class="journal-chip alert">Migrada ${entry.metadata.migrationCount} vezes · simplifique ou divida</span>`);
  const history = entry.migrationHistory.length ? `<span>${entry.migrationHistory.map(item => item.fromDate.slice(5).replace('-','/') + ' → ' + item.toDate.slice(5).replace('-','/')).join(' · ')}</span>` : '';
  return `<article class="journal-entry ${completed ? 'is-done' : ''} ${muted ? 'is-muted' : ''} ${entry.metadata.isPrivate ? 'is-private' : ''}" data-journal-entry="${escapeHtml(entry.id)}"><div class="journal-mark" title="${escapeHtml(status ? JOURNAL_STATUS_LABELS[status] : JOURNAL_TYPE_LABELS[entry.entryType])}">${mark}</div><div class="journal-entry-main"><div class="journal-entry-content ${journalRuntime.concealPreviews && entry.metadata.isPrivate ? 'concealed' : ''}">${escapeHtml(entry.content)}</div><div class="journal-entry-meta"><span>${escapeHtml(JOURNAL_TYPE_LABELS[entry.entryType])}${status ? ` · ${escapeHtml(JOURNAL_STATUS_LABELS[status])}` : ''}</span><span>${new Intl.DateTimeFormat('pt-BR',{hour:'2-digit',minute:'2-digit'}).format(new Date(entry.createdAt))}</span>${entry.mood ? `<span>${escapeHtml(JOURNAL_MOODS[entry.mood])}</span>` : ''}${entry.energy ? `<span>Energia ${entry.energy}/5</span>` : ''}${history}</div>${chips.length ? `<div class="journal-entry-chips">${chips.join('')}</div>` : ''}</div><div class="journal-entry-actions">${entry.entryType === 'task' && ['open','scheduled','delegated'].includes(status) ? `<button type="button" data-journal-complete="${entry.id}">✓ Concluir</button>` : ''}<details><summary aria-label="Mais ações">•••</summary><div class="journal-menu"><button type="button" data-journal-edit="${entry.id}">Editar</button>${entry.entryType === 'task' && ['open','scheduled','delegated'].includes(status) ? `<button type="button" data-journal-migrate="${entry.id}">Migrar ou decidir</button>` : ''}<button type="button" data-journal-transform="${entry.id}">Transformar…</button><button type="button" data-journal-comment="${entry.id}">Adicionar comentário</button><button type="button" data-journal-archive="${entry.id}">Arquivar</button><button class="danger" type="button" data-journal-delete="${entry.id}">Excluir permanentemente</button></div></details></div></article>`;
}

function renderJournalDay() {
  const entries = journalModel.filterEntries(journalModel.entriesForDate(state.data, journalRuntime.date), { query:journalRuntime.search, entryType:journalRuntime.type, taskStatus:journalRuntime.status, signifier:journalRuntime.signifier, collectionId:journalRuntime.collection });
  const all = journalModel.entriesForDate(state.data, journalRuntime.date);
  const tasks = all.filter(item => item.entryType === 'task'); const completed = tasks.filter(item => item.taskStatus === 'completed').length;
  const sessions = journalCompletedSessions(journalRuntime.date); const focused = sessions.reduce((sum,item) => sum + Number(item.durationMs || 0), 0);
  const day = journalDay(); const refs = journalRefs();
  journalSurface.innerHTML = `<section class="journal-panel"><div class="journal-day-head"><div class="journal-nav"><button type="button" data-journal-date="-1" aria-label="Dia anterior">←</button><button type="button" data-journal-today>Hoje</button><button type="button" data-journal-date="1" aria-label="Próximo dia">→</button></div><div class="journal-day-title"><span>${journalRuntime.date === journalModel.dateKey() ? 'Hoje' : 'Diário'}</span><h3>${escapeHtml(journalDateLabel(journalRuntime.date))}</h3></div><div class="journal-stats"><div class="journal-stat"><strong>${all.length}</strong><span>entradas</span></div><div class="journal-stat"><strong>${completed}/${tasks.length}</strong><span>tarefas</span></div><div class="journal-stat"><strong>${journalDuration(focused)}</strong><span>em foco</span></div></div></div><form class="journal-intention" id="journalIntentionForm"><input id="journalIntention" maxlength="500" value="${escapeHtml(day.intention)}" placeholder="Qual é a principal intenção para este dia?"><select id="journalIntentionRef"><option value="">Sem vínculo</option>${refs.map(item => `<option value="${item.type}:${item.id}" ${day.intentionRef?.type === item.type && day.intentionRef?.id === item.id ? 'selected' : ''}>${escapeHtml(item.detail)} · ${escapeHtml(item.title)}</option>`).join('')}</select><button type="submit">Salvar intenção</button></form></section><section class="journal-panel"><form class="journal-capture" id="journalCaptureForm"><input id="journalCaptureInput" maxlength="5000" autocomplete="off" placeholder="Registre algo… use /tarefa, /nota, /aprendizado…" aria-label="Captura rápida"><select id="journalCaptureType">${Object.entries(JOURNAL_TYPE_LABELS).map(([value,label]) => `<option value="${value}" ${value === 'note' ? 'selected' : ''}>${label}</option>`).join('')}</select><button type="submit">Registrar</button></form><p class="journal-capture-hint">Enter salva e mantém o campo disponível. Shift+Enter pode ser usado ao editar uma entrada.</p></section><section class="journal-panel"><div class="journal-section-head"><div><div class="eyebrow">Linha do tempo</div><h3>O que ocupou este dia</h3></div><button class="secondary-btn" type="button" data-journal-close-day>Encerrar o dia</button></div><div class="journal-tools"><input id="journalSearch" type="search" value="${escapeHtml(journalRuntime.search)}" placeholder="Buscar texto, tags ou comentários"><select id="journalFilterType"><option value="">Todos os tipos</option>${Object.entries(JOURNAL_TYPE_LABELS).map(([value,label]) => `<option value="${value}" ${journalRuntime.type === value ? 'selected' : ''}>${label}</option>`).join('')}</select><select id="journalFilterStatus"><option value="">Todos os estados</option>${Object.entries(JOURNAL_STATUS_LABELS).map(([value,label]) => `<option value="${value}" ${journalRuntime.status === value ? 'selected' : ''}>${label}</option>`).join('')}</select><select id="journalFilterSignifier"><option value="">Todos os marcadores</option>${Object.entries(JOURNAL_SIGNIFIER_LABELS).map(([value,label]) => `<option value="${value}" ${journalRuntime.signifier === value ? 'selected' : ''}>${label}</option>`).join('')}</select><select id="journalFilterCollection"><option value="">Todas as coleções</option>${state.data.journalCollections.map(item => `<option value="${item.id}" ${journalRuntime.collection === item.id ? 'selected' : ''}>${escapeHtml(item.title)}</option>`).join('')}</select></div><div class="journal-timeline" id="journalTimeline">${entries.length ? entries.map(journalEntryMarkup).join('') : `<div class="journal-empty"><strong>Nenhuma entrada neste recorte.</strong>Registre algo ou ajuste os filtros.</div>`}</div></section>`;
  journalIntentionForm.addEventListener('submit', event => { event.preventDefault(); const value = journalIntentionRef.value; const [type,id] = value ? value.split(':') : [null,null]; state.data = journalModel.upsertDailyJournal(state.data, journalRuntime.date, { intention:journalIntention.value, intentionRef:type ? {type,id} : null }); journalSave('Intenção do dia salva'); });
  journalCaptureForm.addEventListener('submit', event => { event.preventDefault(); journalCreateFromQuick(); });
  journalCaptureInput.addEventListener('keydown', event => { if (event.key === 'Enter' && !event.shiftKey) { event.preventDefault(); journalCreateFromQuick(); } });
  ['Search','FilterType','FilterStatus','FilterSignifier','FilterCollection'].forEach(name => document.getElementById(`journal${name}`)?.addEventListener(name === 'Search' ? 'input' : 'change', journalReadFilters));
  document.getElementById('journalCaptureInput')?.focus({ preventScroll:true });
}

function journalReadFilters() { journalRuntime.search = journalSearch?.value || ''; journalRuntime.type = journalFilterType?.value || ''; journalRuntime.status = journalFilterStatus?.value || ''; journalRuntime.signifier = journalFilterSignifier?.value || ''; journalRuntime.collection = journalFilterCollection?.value || ''; renderJournalDay(); }
function journalCreateFromQuick() {
  const parsed = journalParseCapture(journalCaptureInput.value, journalCaptureType.value); if (!parsed.content) return;
  const entry = journalModel.createEntry(parsed.content, { entryType:parsed.entryType, date:journalRuntime.date }); state.data.journalEntries.unshift(entry);
  const day = journalDay(); state.data = journalModel.upsertDailyJournal(state.data, journalRuntime.date, { entryIds:[...day.entryIds,entry.id] }); journalEmit('journal:entry-created', entry); journalSave('Entrada registrada');
  requestAnimationFrame(() => { const input = document.getElementById('journalCaptureInput'); if (input) { input.value = ''; input.focus(); } });
}

function journalMonthPlan() {
  let plan = state.data.journalMonthlyPlans.find(item => item.month === journalRuntime.month);
  if (!plan) { const now = journalNow(); plan = { id:`journal_month_${journalRuntime.month}`, schemaVersion:1, month:journalRuntime.month, intention:'', priorities:[], review:{}, reviewedAt:null, createdAt:now, updatedAt:now }; state.data.journalMonthlyPlans.push(plan); }
  return plan;
}
function renderJournalMonth() {
  const plan = journalMonthPlan(); const [year,month] = journalRuntime.month.split('-').map(Number); const days = new Date(year,month,0).getDate();
  const entries = state.data.journalEntries.filter(item => item.date.startsWith(journalRuntime.month));
  journalSurface.innerHTML = `<div class="journal-split"><section class="journal-panel"><div class="journal-month-head"><div><div class="eyebrow">Linha temporal</div><h3>${new Intl.DateTimeFormat('pt-BR',{month:'long',year:'numeric'}).format(new Date(year,month-1,1))}</h3></div><div class="journal-nav"><button type="button" data-journal-month="-1">←</button><button type="button" data-journal-month-today>Atual</button><button type="button" data-journal-month="1">→</button></div></div><div class="journal-month-grid">${Array.from({length:days},(_,i)=>{const key=`${journalRuntime.month}-${String(i+1).padStart(2,'0')}`;const found=entries.filter(item=>item.date===key);return `<button type="button" class="journal-month-day ${found.length?'has-items':''}" data-journal-open-date="${key}"><strong>${i+1}</strong><span>${found.length ? `${found.length} entrada${found.length>1?'s':''}` : '—'}</span></button>`}).join('')}</div></section><section class="journal-panel"><div class="journal-section-head"><div><div class="eyebrow">Direção</div><h3>Prioridades do mês</h3></div></div><form class="journal-inline-form" id="journalPriorityForm"><input id="journalPriorityInput" maxlength="500" placeholder="Entrega, estudo, livro ou decisão"><select id="journalPriorityRef"><option value="">Sem vínculo</option>${journalRefs().map(item=>`<option value="${item.type}:${item.id}">${escapeHtml(item.detail)} · ${escapeHtml(item.title)}</option>`).join('')}</select><button>Adicionar</button></form><div class="journal-list">${plan.priorities.length ? plan.priorities.map(item=>`<article class="journal-list-row"><div><strong>${escapeHtml(item.content)}</strong><span>${item.status==='completed'?'Concluída':'Aberta'}${item.linkedRefs[0]?` · ${escapeHtml(journalRefLabel(item.linkedRefs[0]))}`:''}</span></div><div><button data-journal-priority-toggle="${item.id}">${item.status==='completed'?'Reabrir':'Concluir'}</button><button data-journal-priority-delete="${item.id}">Excluir</button></div></article>`).join(''):'<div class="journal-empty"><strong>Nenhuma prioridade.</strong>Escolha poucas direções relevantes.</div>'}</div><details style="margin-top:14px"><summary class="secondary-btn">Revisão mensal opcional</summary><form id="journalMonthReviewForm" class="journal-review" style="margin-top:12px">${[['worked','O que funcionou?'],['notWorked','O que não funcionou?'],['impact','O que produziu mais impacto?'],['waste','O que consumiu tempo sem gerar valor?'],['learned','O que aprendi?'],['drop','Que compromisso não faz mais sentido?'],['next','Intenção do próximo mês']].map(([key,label])=>`<label>${label}<textarea name="${key}" maxlength="1200">${escapeHtml(plan.review?.[key]||'')}</textarea></label>`).join('')}<button class="primary-btn" type="submit">Concluir revisão mensal</button></form></details></section></div>`;
  journalPriorityForm.addEventListener('submit', event=>{event.preventDefault();const content=journalPriorityInput.value.trim();if(!content)return;const value=journalPriorityRef.value;const [type,id]=value?value.split(':'):[null,null];const now=journalNow();plan.priorities.push({id:`priority_${Date.now()}`,content,status:'open',linkedRefs:type?[{type,id}]:[],createdAt:now,updatedAt:now});plan.updatedAt=now;journalSave('Prioridade mensal adicionada');});
  journalMonthReviewForm.addEventListener('submit', event=>{event.preventDefault();plan.review=Object.fromEntries(new FormData(event.currentTarget));plan.reviewedAt=journalNow();plan.updatedAt=plan.reviewedAt;CompassoFeatures.emit('journal:month-reviewed',{id:plan.id,month:plan.month,timestamp:plan.reviewedAt});journalSave('Revisão mensal concluída');});
}

function renderJournalFuture() {
  const items = state.data.journalFutureItems.filter(item => item.status === 'planned').sort((a,b)=>String(a.scheduledFor||'zzzz').localeCompare(String(b.scheduledFor||'zzzz')));
  journalSurface.innerHTML = `<section class="journal-panel"><div class="journal-section-head"><div><div class="eyebrow">Planejamento futuro</div><h3>Guardar sem poluir o dia</h3><p>Ao chegar o momento, escolha conscientemente onde cada item entra.</p></div></div><form class="journal-inline-form" id="journalFutureForm"><input id="journalFutureContent" maxlength="5000" required placeholder="Tarefa, evento ou intenção futura"><select id="journalFutureSchedule"><option value="month">Mês</option><option value="quarter">Trimestre</option><option value="date">Data específica</option><option value="someday">Algum dia</option><option value="undated">Sem data</option></select><button>Guardar</button><input id="journalFutureWhen" placeholder="2026-08, 2026-T3 ou AAAA-MM-DD"></form><div class="journal-list">${items.length?items.map(item=>`<article class="journal-list-row"><div><strong>${escapeHtml(item.content)}</strong><span>${escapeHtml({month:'Mês',quarter:'Trimestre',date:'Data',someday:'Algum dia',undated:'Sem data'}[item.scheduleType])}${item.scheduledFor?` · ${escapeHtml(item.scheduledFor)}`:''}</span></div><div><button data-journal-future-move="${item.id}">Mover para hoje</button><button data-journal-future-keep="${item.id}">Escolher dia</button><button data-journal-future-archive="${item.id}">Arquivar</button></div></article>`).join(''):'<div class="journal-empty"><strong>Nenhum item futuro.</strong>O que ainda não pertence ao presente pode descansar aqui.</div>'}</div></section>`;
  journalFutureForm.addEventListener('submit',event=>{event.preventDefault();const item=journalModel.createFutureItem(journalFutureContent.value,{scheduleType:journalFutureSchedule.value,scheduledFor:journalFutureWhen.value});state.data.journalFutureItems.unshift(item);journalSave('Item guardado no futuro');});
}

function renderJournalCollections() {
  journalSurface.innerHTML = `<section class="journal-panel"><div class="journal-section-head"><div><div class="eyebrow">Coleções</div><h3>Agrupamentos temáticos simples</h3></div></div><form class="journal-inline-form" id="journalCollectionForm"><input id="journalCollectionTitle" maxlength="120" required placeholder="Ex.: decisões do projeto"><input id="journalCollectionDescription" maxlength="1000" placeholder="Descrição opcional"><button>Criar coleção</button></form><div class="journal-list">${state.data.journalCollections.length?state.data.journalCollections.map(item=>{const count=state.data.journalEntries.filter(entry=>entry.collectionIds.includes(item.id)).length;return `<article class="journal-list-row"><div><strong>${escapeHtml(item.title)}</strong><span>${escapeHtml(item.description||'Sem descrição')} · ${count} entradas · ${escapeHtml(item.status)}</span></div><div><button data-journal-collection-open="${item.id}">Ver entradas</button><button data-journal-collection-archive="${item.id}">${item.status==='archived'?'Reativar':'Arquivar'}</button></div></article>`}).join(''):'<div class="journal-empty"><strong>Nenhuma coleção.</strong>Crie somente quando um tema realmente precisar de continuidade.</div>'}</div></section>`;
  journalCollectionForm.addEventListener('submit',event=>{event.preventDefault();const item=journalModel.createCollection(journalCollectionTitle.value,{description:journalCollectionDescription.value});state.data.journalCollections.unshift(item);journalEmit('journal:collection-created',item);journalSave('Coleção criada');});
}

function renderJournal() {
  document.querySelectorAll('[data-journal-mode]').forEach(button=>button.classList.toggle('active',button.dataset.journalMode===journalRuntime.mode));
  const conceal = document.querySelector('[data-journal-conceal]'); if (conceal) conceal.textContent = journalRuntime.concealPreviews ? 'Mostrar prévias' : 'Ocultar prévias';
  const open = state.data.journalEntries.filter(item=>item.entryType==='task'&&['open','scheduled','delegated'].includes(item.taskStatus)).length; const badge=document.getElementById('journalBadge');if(badge)badge.textContent=open||'';
  if (journalRuntime.mode === 'month') renderJournalMonth(); else if (journalRuntime.mode === 'future') renderJournalFuture(); else if (journalRuntime.mode === 'collections') renderJournalCollections(); else renderJournalDay();
  renderJournalIntegrations();
}

function journalOpenEntry(entry = null) {
  journalRuntime.editingId = entry?.id || null; journalEntryTitle.textContent = entry ? 'Editar entrada' : 'Nova entrada'; journalEntryContent.value=entry?.content||''; journalEntryType.value=entry?.entryType||'note'; journalEntryDate.value=entry?.date||journalRuntime.date; journalEntryStatus.value=entry?.taskStatus||'open'; journalEntryStatus.disabled=(entry?.entryType||journalEntryType.value)!=='task'; journalEntryRef.innerHTML=`<option value="">Sem vínculo</option>${journalRefs().map(item=>`<option value="${item.type}:${item.id}">${escapeHtml(item.detail)} · ${escapeHtml(item.title)}</option>`).join('')}`; const linked=entry?.linkedRefs?.[0];journalEntryRef.value=linked?`${linked.type}:${linked.id}`:''; journalEntryCollection.innerHTML=`<option value="">Sem coleção</option>${state.data.journalCollections.map(item=>`<option value="${item.id}">${escapeHtml(item.title)}</option>`).join('')}`;journalEntryCollection.value=entry?.collectionIds?.[0]||'';journalEntryMood.value=entry?.mood||'';journalEntryEnergy.value=entry?.energy||'';journalEntryTags.value=(entry?.tags||[]).join(', ');journalEntryPinned.checked=Boolean(entry?.metadata?.isPinned);journalEntryPrivate.checked=entry?.metadata?.isPrivate!==false;document.querySelectorAll('[name="journalSignifier"]').forEach(input=>input.checked=entry?.signifiers?.includes(input.value));journalEntryDialog.showModal();journalEntryContent.focus();
}
function journalSaveEntryForm() {
  const link=journalEntryRef.value;const [type,id]=link?link.split(':'):[null,null];const patch={content:journalEntryContent.value,entryType:journalEntryType.value,taskStatus:journalEntryStatus.value,date:journalEntryDate.value,signifiers:[...document.querySelectorAll('[name="journalSignifier"]:checked')].map(input=>input.value),tags:journalEntryTags.value.split(',').map(value=>value.trim()).filter(Boolean),mood:journalEntryMood.value,energy:journalEntryEnergy.value,collectionIds:journalEntryCollection.value?[journalEntryCollection.value]:[],linkedRefs:type?[{type,id}]:[],isPinned:journalEntryPinned.checked,isPrivate:journalEntryPrivate.checked};let entry=journalRuntime.editingId?journalModel.updateEntry(journalEntry(journalRuntime.editingId),patch):journalModel.createEntry(patch.content,patch);journalReplace(entry);journalEntryDialog.close();journalEmit(journalRuntime.editingId?'journal:entry-updated':'journal:entry-created',entry);journalRuntime.date=entry.date;journalSave(journalRuntime.editingId?'Entrada atualizada':'Entrada criada');
}
function journalOpenMigration(entry) { journalRuntime.migratingId=entry.id;journalMigrationContent.textContent=entry.content;journalMigrationDate.value=journalDateOffset(entry.date,1);journalMigrationDialog.showModal(); }
function journalApplyMigration() {
  const entry=journalEntry(journalRuntime.migratingId);if(!entry)return;const decision=journalMigrationDecision.value;const reason=journalMigrationReason.value;
  if(['tomorrow','date'].includes(decision)){const target=decision==='tomorrow'?journalDateOffset(entry.date,1):journalMigrationDate.value;const result=journalModel.migrateTask(entry,target,{reason});journalReplace(result.original);state.data.journalEntries.unshift(result.destination);journalEmit('journal:task-migrated',result.destination,{fromId:entry.id,fromDate:entry.date,toDate:target,reason});}
  else if(decision==='future'){state.data.journalFutureItems.unshift(journalModel.createFutureItem(entry.content,{entryType:'task',scheduleType:'undated',linkedRefs:entry.linkedRefs}));journalReplace(journalModel.setTaskStatus(entry,'scheduled'));}
  else if(decision==='delegate')journalReplace(journalModel.setTaskStatus(entry,'delegated'));
  else if(decision==='cancel')journalReplace(journalModel.setTaskStatus(entry,'cancelled'));
  else if(decision==='archive')journalReplace(journalModel.setTaskStatus(entry,'archived'));
  else if(decision==='project'){const result=journalTransformTo(entry,'action','Projeto: próximo passo a definir');journalReplace(result);}
  journalMigrationDialog.close();journalSave('Decisão registrada');
}

function journalOpenTransform(entry) { journalRuntime.transformId=entry.id;journalTransformContent.textContent=entry.content;journalTransformExtra.value='';journalTransformDialog.showModal(); }
function journalTransformTo(entry,target,extra='') {
  const now=journalNow();let resultRef=null;
  if(target==='note'){const folder=state.data.folders.find(item=>item.id==='f-inbox')||state.data.folders[0];const note={id:`n${Date.now()}`,title:entry.content.slice(0,80),folder:folder?.id||null,domain:'inbox',linkedItemId:null,tags:[...entry.tags,'journal'].filter(Boolean),updated:journalModel.dateKey(),content:`# ${entry.content.slice(0,80)}\n\n${entry.content}\n\n## Origem\n\nJournal de ${entry.date}.`,sourceJournalEntryId:entry.id,createdAt:now,updatedAt:now};state.data.notes.push(note);resultRef={type:'note',id:note.id};}
  if(target==='action'){const plan=typeof todayPlan==='function'?todayPlan():null;if(plan){const linked=entry.linkedRefs.find(ref=>['reading','study','goal'].includes(ref.type));const action={id:`a${Date.now()}`,type:'custom',title:entry.content,domain:linked?.type||null,itemId:linked?.id||null,completedAt:null,createdAt:now,sourceJournalEntryId:entry.id};plan.items.push(action);resultRef={type:'action',id:action.id};}}
  if(target==='capture'&&globalThis.CompassoCaptureModel){const capture=globalThis.CompassoCaptureModel.create(entry.content,{source:{type:'manual',id:entry.id},linkedRefs:entry.linkedRefs.filter(ref=>['reading','study','goal','action','session','note'].includes(ref.type))});state.data.captures.unshift(capture);resultRef={type:'capture',id:capture.id};}
  if(target==='recall'){const card={id:`r${Date.now()}`,schemaVersion:2,sourceType:'journal',sourceId:entry.id,domain:null,itemId:null,prompt:entry.entryType==='question'?entry.content:`Explique com suas palavras: ${entry.content}`,answer:String(extra||'Resposta a completar').trim(),reviewCount:0,intervalDays:0,dueAt:now,lastReviewedAt:null,lastRating:null,reviewHistory:[],createdAt:now,updatedAt:now};state.data.reviewItems=Array.isArray(state.data.reviewItems)?state.data.reviewItems:[];state.data.reviewItems.unshift(card);resultRef={type:'recall',id:card.id};}
  if(target==='evidence'){const linkedSession=entry.linkedRefs.find(ref=>ref.type==='session');const session=(state.data.sessions||[]).find(item=>item.id===linkedSession?.id);const evidence={id:`e${Date.now()}`,schemaVersion:1,sessionId:session?.id||null,itemId:session?.itemId||null,domain:session?.domain||null,type:'insight',summary:entry.content.slice(0,500),details:String(extra||'').trim(),sourceJournalEntryId:entry.id,createdAt:now,updatedAt:now};state.data.evidence=Array.isArray(state.data.evidence)?state.data.evidence:[];state.data.evidence.unshift(evidence);resultRef={type:'evidence',id:evidence.id};}
  const updated=journalModel.updateEntry(entry,{});updated.resultRef=resultRef;updated.updatedAt=now;journalEmit('journal:entry-transformed',updated,{resultRef});return updated;
}
function journalApplyTransform(){const entry=journalEntry(journalRuntime.transformId);if(!entry)return;const updated=journalTransformTo(entry,journalTransformTarget.value,journalTransformExtra.value);journalReplace(updated);journalTransformDialog.close();journalSave('Entrada transformada com a origem preservada');}

function journalOpenCloseDay(){const entries=journalModel.entriesForDate(state.data,journalRuntime.date);const tasks=entries.filter(item=>item.entryType==='task'&&['open','scheduled','delegated'].includes(item.taskStatus));const sessions=journalCompletedSessions(journalRuntime.date);journalCloseSummary.textContent=`${entries.length} entradas · ${sessions.length} sessões · ${journalDuration(sessions.reduce((sum,item)=>sum+Number(item.durationMs||0),0))} em foco · ${state.data.notes.filter(item=>journalModel.dateKey(item.createdAt||item.updated||'')===journalRuntime.date).length} notas criadas.`;journalCloseTasks.innerHTML=tasks.length?tasks.map(item=>`<div class="journal-close-row"><span>${escapeHtml(item.content)}</span><select data-journal-close-decision="${item.id}"><option value="keep">Manter no dia</option><option value="complete">Concluir</option><option value="tomorrow">Migrar para amanhã</option><option value="date">Escolher outra data</option><option value="future">Mover para o futuro</option><option value="delegate">Delegar</option><option value="cancel">Cancelar</option><option value="archive">Arquivar</option></select><input type="date" data-journal-close-date="${item.id}" value="${journalDateOffset(item.date,1)}"></div>`).join(''):'<div class="journal-empty">Nenhuma tarefa aberta exige decisão.</div>';journalCloseForm.reset();journalCloseDialog.showModal();}
function journalApplyClose(){document.querySelectorAll('[data-journal-close-decision]').forEach(select=>{const entry=journalEntry(select.dataset.journalCloseDecision);if(!entry||select.value==='keep')return;if(select.value==='complete')journalReplace(journalModel.setTaskStatus(entry,'completed'));else if(['tomorrow','date'].includes(select.value)){const target=select.value==='tomorrow'?journalDateOffset(entry.date,1):document.querySelector(`[data-journal-close-date="${entry.id}"]`).value;const result=journalModel.migrateTask(entry,target,{reason:'daily_close'});journalReplace(result.original);state.data.journalEntries.unshift(result.destination);journalEmit('journal:task-migrated',result.destination,{fromId:entry.id,toDate:target,reason:'daily_close'});}else if(select.value==='future'){state.data.journalFutureItems.unshift(journalModel.createFutureItem(entry.content,{entryType:'task',scheduleType:'undated',linkedRefs:entry.linkedRefs}));journalReplace(journalModel.setTaskStatus(entry,'scheduled'));}else journalReplace(journalModel.setTaskStatus(entry,{delegate:'delegated',cancel:'cancelled',archive:'archived'}[select.value]));});state.data=journalModel.closeDay(state.data,journalRuntime.date,Object.fromEntries(new FormData(journalCloseForm)));journalCloseDialog.close();CompassoFeatures.emit('journal:day-closed',{date:journalRuntime.date,timestamp:journalNow()});journalSave('Dia encerrado com decisões registradas');}

function journalSessionCapture(event){event.preventDefault();const session=sessionActive?.();const input=document.getElementById('journalSessionInput');const type=document.getElementById('journalSessionType');if(!session||!input?.value.trim())return;const mapping={note:'note',question:'question',insight:'learning',distraction:'note',next:'task',blocker:'note'};const signifiers=type.value==='blocker'?['blocked']:[];const tags=['sessão',type.value];const entry=journalModel.createEntry(input.value,{entryType:mapping[type.value]||'note',date:journalModel.dateKey(),signifiers,tags,linkedRefs:[{type:'session',id:session.id},{type:session.domain,id:session.itemId}],source:{type:'session',id:session.id}});state.data.journalEntries.unshift(entry);journalEmit('journal:entry-created',entry,{source:'session'});input.value='';journalSave('Registro da sessão salvo no Journal');}

function renderJournalIntegrations(){
  const today=document.querySelector('#todayView .today-shell');if(today&&!document.getElementById('journalTodayPanel'))today.insertAdjacentHTML('beforeend',`<section class="today-panel journal-today" id="journalTodayPanel"><div class="today-panel-head"><div><div class="eyebrow">Journal de hoje</div><h3>Registros e decisões</h3><p id="journalTodayIntention"></p></div><div><button class="secondary-btn" type="button" data-journal-register>Registrar</button> <button class="quiet-btn" type="button" data-journal-open> Abrir diário</button></div></div><div class="journal-today-summary" id="journalTodaySummary"></div></section>`);
  const todayEntries=journalModel.entriesForDate(state.data,journalModel.dateKey());const todayTasks=todayEntries.filter(item=>item.entryType==='task');if(document.getElementById('journalTodayIntention'))journalTodayIntention.textContent=journalDay(journalModel.dateKey()).intention||'Nenhuma intenção registrada para hoje.';if(document.getElementById('journalTodaySummary'))journalTodaySummary.innerHTML=`<div><strong>${todayEntries.length}</strong><span>entradas</span></div><div><strong>${todayTasks.filter(item=>['open','scheduled','delegated'].includes(item.taskStatus)).length}</strong><span>tarefas abertas</span></div><div><strong>${todayTasks.filter(item=>item.taskStatus==='completed').length}</strong><span>concluídas</span></div><div><strong>${todayEntries.filter(item=>item.entryType==='reflection').length}</strong><span>reflexões</span></div>`;
  const weekly=document.getElementById('weeklyReviewForm')?.closest('.weekly-panel');if(weekly&&!document.getElementById('journalWeeklyPanel'))weekly.insertAdjacentHTML('beforebegin',`<section class="weekly-panel" id="journalWeeklyPanel"><div class="weekly-panel-head"><div><div class="eyebrow">Revisar Journal</div><h3>Atenção, migrações e aprendizados</h3><p>Use estes sinais como hipóteses para decidir a próxima semana.</p></div></div><div class="journal-weekly-list" id="journalWeeklySummary"></div></section>`);
  const range=typeof weeklyRange==='function'?weeklyRange():null;const weekEntries=range?state.data.journalEntries.filter(item=>item.date>=journalModel.dateKey(range.start)&&item.date<=journalModel.dateKey(range.end)):[];if(document.getElementById('journalWeeklySummary'))journalWeeklySummary.innerHTML=`<div><strong>${weekEntries.length}</strong><span>entradas importantes: ${weekEntries.filter(item=>item.signifiers.includes('important')||item.signifiers.includes('priority')).length}</span></div><div><strong>${weekEntries.filter(item=>item.entryType==='task'&&['open','scheduled','delegated'].includes(item.taskStatus)).length}</strong><span>tarefas abertas</span></div><div><strong>${weekEntries.filter(item=>item.metadata.migrationCount>0).length}</strong><span>tarefas migradas</span></div><div><strong>${weekEntries.filter(item=>item.entryType==='decision').length}</strong><span>decisões</span></div><div><strong>${weekEntries.filter(item=>item.entryType==='learning').length}</strong><span>aprendizados</span></div><div><strong>${weekEntries.filter(item=>item.entryType==='question').length}</strong><span>perguntas</span></div>`;
  const startBody=document.querySelector('#sessionStartDialog .session-dialog-body');if(startBody&&!document.getElementById('journalSessionIntentWrap'))startBody.insertAdjacentHTML('beforeend',`<div class="field" id="journalSessionIntentWrap"><label for="journalSessionIntent">Intenção do Journal (opcional)</label><select id="journalSessionIntent"></select></div>`);if(document.getElementById('journalSessionIntent')){const intents=state.data.journalEntries.filter(item=>item.entryType==='task'&&['open','scheduled'].includes(item.taskStatus)).slice(0,30);journalSessionIntent.innerHTML=`<option value="">Sem intenção vinculada</option>${intents.map(item=>`<option value="${item.id}">${escapeHtml(item.content)}</option>`).join('')}`;}
  const banner=document.getElementById('sessionBanner');if(banner&&!document.getElementById('journalSessionCapture'))banner.insertAdjacentHTML('beforeend',`<form class="journal-session-capture" id="journalSessionCapture"><select id="journalSessionType"><option value="note">Nota</option><option value="question">Dúvida</option><option value="distraction">Distração</option><option value="insight">Insight</option><option value="next">Próximo passo</option><option value="blocker">Bloqueio</option></select><input id="journalSessionInput" maxlength="5000" placeholder="Registrar sem sair da sessão"><button>Salvar</button></form>`);
  const finishBody=document.querySelector('#sessionFinishDialog .session-dialog-body');if(finishBody&&!document.getElementById('journalSessionFinishEntries'))finishBody.insertAdjacentHTML('beforeend','<div class="session-summary" id="journalSessionFinishEntries" hidden></div>');const active=typeof sessionActive==='function'?sessionActive():null;if(active&&document.getElementById('journalSessionFinishEntries')){const entries=state.data.journalEntries.filter(item=>item.linkedRefs.some(ref=>ref.type==='session'&&ref.id===active.id));journalSessionFinishEntries.hidden=!entries.length;journalSessionFinishEntries.innerHTML=entries.length?`<strong>${entries.length} registro(s) no Journal desta sessão</strong><br>${entries.map(item=>escapeHtml(item.content)).join('<br>')}`:'';}
}

journalInstallStyles();journalInstallUi();
CompassoFeatures.register('journal',{order:850,afterRender:renderJournal});
CompassoFeatures.action('[data-journal-mode]',({target})=>{journalRuntime.mode=target.dataset.journalMode;renderJournal()});
CompassoFeatures.action('[data-journal-date]',({target})=>{journalRuntime.date=journalDateOffset(journalRuntime.date,Number(target.dataset.journalDate));renderJournalDay()});
CompassoFeatures.action('[data-journal-today]',()=>{journalRuntime.date=journalModel.dateKey();renderJournalDay()});
CompassoFeatures.action('[data-journal-month]',({target})=>{journalRuntime.month=journalMonthOffset(journalRuntime.month,Number(target.dataset.journalMonth));renderJournalMonth()});
CompassoFeatures.action('[data-journal-month-today]',()=>{journalRuntime.month=journalModel.dateKey().slice(0,7);renderJournalMonth()});
CompassoFeatures.action('[data-journal-open-date]',({target})=>{journalRuntime.date=target.dataset.journalOpenDate;journalRuntime.mode='day';renderJournal()});
CompassoFeatures.action('[data-journal-edit]',({target})=>journalOpenEntry(journalEntry(target.dataset.journalEdit)));
CompassoFeatures.action('[data-journal-complete]',({target})=>{const entry=journalModel.setTaskStatus(journalEntry(target.dataset.journalComplete),'completed');journalReplace(entry);journalEmit('journal:task-completed',entry);journalSave('Tarefa concluída')});
CompassoFeatures.action('[data-journal-migrate]',({target})=>journalOpenMigration(journalEntry(target.dataset.journalMigrate)));
CompassoFeatures.action('[data-journal-transform]',({target})=>journalOpenTransform(journalEntry(target.dataset.journalTransform)));
CompassoFeatures.action('[data-journal-comment]',({target})=>{const value=prompt('Comentário desta entrada:');if(!value?.trim())return;const entry=journalModel.addComment(journalEntry(target.dataset.journalComment),value);journalReplace(entry);journalEmit('journal:entry-updated',entry);journalSave('Comentário adicionado')});
CompassoFeatures.action('[data-journal-archive]',({target})=>{let entry=journalEntry(target.dataset.journalArchive);entry=entry.entryType==='task'?journalModel.setTaskStatus(entry,'archived'):journalModel.updateEntry(entry,{});if(entry.entryType!=='task')entry.archivedAt=journalNow();journalReplace(entry);journalEmit('journal:entry-archived',entry);journalSave('Entrada arquivada')});
CompassoFeatures.action('[data-journal-delete]',({target})=>{if(!confirm('Excluir permanentemente esta entrada e seus vínculos no Journal?'))return;const entry=journalEntry(target.dataset.journalDelete);state.data.journalEntries=state.data.journalEntries.filter(item=>item.id!==entry.id);Object.values(state.data.dailyJournals).forEach(day=>day.entryIds=day.entryIds.filter(id=>id!==entry.id));state.data.journalCollections.forEach(collection=>collection.entryIds=collection.entryIds.filter(id=>id!==entry.id));journalEmit('journal:entry-deleted',entry);journalSave('Entrada excluída permanentemente')});
CompassoFeatures.action('[data-journal-close-day]',()=>journalOpenCloseDay());
CompassoFeatures.action('[data-journal-close]',({target})=>document.getElementById(target.dataset.journalClose)?.close());
CompassoFeatures.action('[data-journal-priority-toggle]',({target})=>{const plan=journalMonthPlan();const item=plan.priorities.find(value=>value.id===target.dataset.journalPriorityToggle);if(item){item.status=item.status==='completed'?'open':'completed';item.updatedAt=journalNow();plan.updatedAt=item.updatedAt;journalSave('Prioridade mensal atualizada')}});
CompassoFeatures.action('[data-journal-priority-delete]',({target})=>{const plan=journalMonthPlan();plan.priorities=plan.priorities.filter(item=>item.id!==target.dataset.journalPriorityDelete);plan.updatedAt=journalNow();journalSave('Prioridade mensal excluída')});
CompassoFeatures.action('[data-journal-future-move]',({target})=>journalMoveFuture(target.dataset.journalFutureMove,journalModel.dateKey()));
CompassoFeatures.action('[data-journal-future-keep]',({target})=>{const key=prompt('Data no formato AAAA-MM-DD:',journalModel.dateKey());if(/^\d{4}-\d{2}-\d{2}$/.test(key||''))journalMoveFuture(target.dataset.journalFutureKeep,key)});
CompassoFeatures.action('[data-journal-future-archive]',({target})=>{const item=state.data.journalFutureItems.find(value=>value.id===target.dataset.journalFutureArchive);if(item){item.status='archived';item.archivedAt=journalNow();item.updatedAt=item.archivedAt;journalSave('Item futuro arquivado')}});
CompassoFeatures.action('[data-journal-collection-open]',({target})=>{journalRuntime.collection=target.dataset.journalCollectionOpen;journalRuntime.mode='day';journalRuntime.date=journalModel.dateKey();renderJournal()});
CompassoFeatures.action('[data-journal-collection-archive]',({target})=>{const item=state.data.journalCollections.find(value=>value.id===target.dataset.journalCollectionArchive);if(item){item.status=item.status==='archived'?'active':'archived';item.archivedAt=item.status==='archived'?journalNow():null;item.updatedAt=journalNow();journalEmit('journal:collection-updated',item);journalSave('Coleção atualizada')}});
CompassoFeatures.action('[data-journal-open]',()=>{switchView('journal');journalRuntime.mode='day';journalRuntime.date=journalModel.dateKey();renderJournal()});
CompassoFeatures.action('[data-journal-register]',()=>{switchView('journal');journalRuntime.mode='day';journalRuntime.date=journalModel.dateKey();renderJournal();requestAnimationFrame(()=>journalCaptureInput?.focus())});
CompassoFeatures.action('[data-journal-conceal]',()=>{journalRuntime.concealPreviews=!journalRuntime.concealPreviews;localStorage.setItem('compasso.journal.conceal.v1',String(journalRuntime.concealPreviews));renderJournal()});

function journalMoveFuture(id,date){const item=state.data.journalFutureItems.find(value=>value.id===id);if(!item)return;const entry=journalModel.createEntry(item.content,{entryType:item.entryType,date,linkedRefs:item.linkedRefs,source:{type:'migration',id:item.id}});state.data.journalEntries.unshift(entry);item.status='moved';item.updatedAt=journalNow();journalEmit('journal:entry-created',entry,{source:'future'});journalSave('Item movido para o Diário')}

journalEntryType.addEventListener('change',()=>journalEntryStatus.disabled=journalEntryType.value!=='task');
journalEntryForm.addEventListener('submit',event=>{event.preventDefault();journalSaveEntryForm()});
journalMigrationForm.addEventListener('submit',event=>{event.preventDefault();journalApplyMigration()});
journalTransformForm.addEventListener('submit',event=>{event.preventDefault();journalApplyTransform()});
journalCloseForm.addEventListener('submit',event=>{event.preventDefault();journalApplyClose()});
document.addEventListener('submit',event=>{if(event.target.id==='journalSessionCapture')journalSessionCapture(event)});
document.getElementById('sessionStartForm')?.addEventListener('submit',()=>queueMicrotask(()=>{const session=typeof sessionActive==='function'?sessionActive():null;const entry=journalEntry(document.getElementById('journalSessionIntent')?.value);if(session&&entry){session.journalEntryId=entry.id;session.intent=session.intent||entry.content;session.updatedAt=journalNow();window.CompassoStorage?.save?.(STORAGE_KEY,state.data)}}));

JOURNAL_EVENTS.forEach(name => CompassoFeatures.on(name, payload => { if (!payload?.timestamp) console.warn(`[Journal] Evento sem timestamp: ${name}`); }));
globalThis.CompassoJournalFeature = Object.freeze({
  open(date=journalModel.dateKey()){journalRuntime.date=date;journalRuntime.mode='day';switchView('journal');renderJournal()},
  capture(content,options={}){const entry=journalModel.createEntry(content,options);state.data.journalEntries.unshift(entry);journalEmit('journal:entry-created',entry);journalSave('Entrada registrada');return entry},
  metrics(){return journalModel.metrics(state.data.journalEntries)},
  prepareExport(data){const include=document.getElementById('journalExportToggle')?.checked!==false;if(include)return data;const copy=structuredClone(data);['journalEntries','dailyJournals','journalCollections','journalFutureItems','journalMonthlyPlans','journalConflicts','journalSchemaVersion'].forEach(key=>delete copy[key]);return copy}
});
